#include <iostream>

int main() {
    int n, a = 0, b = 1, c;
    std::cout << "Cuantos numeros Fibonacci? ";
    std::cin >> n;
    for (int i = 0; i < n; i++) {
        std::cout << a << " ";
        c = a + b;
        a = b;
        b = c;
    }
    std::cout << std::endl;
    return 0;
}

#include <iostream>

int main() {
    double a, b;
    char op;
    std::cout << "Ingresa operacion (ej: 3 + 5): ";
    std::cin >> a >> op >> b;
    switch(op) {
        case '+': std::cout << a + b; break;
        case '-': std::cout << a - b; break;
        case '*': std::cout << a * b; break;
        case '/': std::cout << a / b; break;
        default: std::cout << "Operador invalido";
    }
    std::cout << std::endl;
    return 0;
}

