#include <iostream>

int main() {
    int n;
    bool primo = true;
    std::cout << "Ingresa un numero: ";
    std::cin >> n;
    for (int i = 2; i * i <= n; i++) {
        if (n % i == 0) { primo = false; break; }
    }
    if (primo && n > 1)
        std::cout << n << " es primo" << std::endl;
    else
        std::cout << n << " no es primo" << std::endl;
    return 0;
}

#include <iostream>

int main() {
    int n, invertido = 0;
    std::cout << "Ingresa un numero: ";
    std::cin >> n;
    while (n > 0) {
        invertido = invertido * 10 + n % 10;
        n /= 10;
    }
    std::cout << "Invertido: " << invertido << std::endl;
    return 0;
}

#include <iostream>
#include <string>

int main() {
    std::string s;
    std::cout << "Ingresa una palabra: ";
    std::cin >> s;
    bool palindromo = true;
    int n = s.length();
    for (int i = 0; i < n / 2; i++) {
        if (s[i] != s[n - 1 - i]) { palindromo = false; break; }
    }
    if (palindromo)
        std::cout << "Es palindromo" << std::endl;
    else
        std::cout << "No es palindromo" << std::endl;
    return 0;
}
